def get_connection_params() -> dict:
    """Get database connection parameters from user."""
    print("\n--- Database Connection Setup ---")
    host = input("Host [localhost]: ").strip() or "localhost"
    port = input("Port [5432]: ").strip() or "5432"
    dbname = input("Database name [postgres]: ").strip() or "postgres"
    user = input("Username [postgres]: ").strip() or "postgres"
    password = getpass.getpass("Password: ")
    return {
        "host": host,
        "port": port,
        "dbname": dbname,
        "user": user,
        "password": password,
    }


def main():
    """Main function for the PostgreSQL Extension Manager Dashboard."""
    print("Welcome to the PostgreSQL Extension Manager")

    params = get_connection_params()
    conn = get_db_connection(**params)

    if conn is None:
        print("Failed to connect to the database. Exiting.")
        return

    print(f"Connected to database '{params['dbname']}' on {params['host']}:{params['port']}")

    try:
        while True:
            print_menu()
            choice = input("Select an option (1-7): ").strip()

            if choice == "1":
                print("\n--- Installed Extensions ---")
                extensions = list_installed_extensions(conn)
                if extensions:
                    print(f"{'Extension Name':<30} {'Version':<15}")
                    print("-" * 45)
                    for name, version in extensions:
                        print(f"{name:<30} {version:<15}")
                else:
                    print("No extensions found or error occurred.")

            elif choice == "2":
                print("\n--- Available Extensions ---")
                extensions = list_available_extensions(conn)
                if extensions:
                    print(f"{'Extension Name':<30} {'Version':<15} {'Description'}")
                    print("-" * 90)
                    for name, version, comment in extensions:
                        desc = (comment or "")[:50]
                        print(f"{name:<30} {version or 'N/A':<15} {desc}")
                else:
                    print("No available extensions found or error occurred.")

            elif choice == "3":
                print("\n--- Install Extension ---")
                ext_name = input("Enter extension name to install: ").strip().lower()
                if ext_name:
                    confirm = input(
                        f"Are you sure you want to install '{ext_name}'? (yes/no): "
                    ).strip().lower()
                    if confirm == "yes":
                        install_extension(conn, ext_name)
                    else:
                        print("Installation cancelled.")
                else:
                    print("No extension name provided.")

            elif choice == "4":
                print("\n--- Uninstall Extension ---")
                ext_name = input("Enter extension name to uninstall: ").strip().lower()
                if ext_name:
                    confirm = input(
                        f"Are you sure you want to uninstall '{ext_name}'? "
                        "This will CASCADE and remove dependent objects! (yes/no): "
                    ).strip().lower()
                    if confirm == "yes":
                        uninstall_extension(conn, ext_name)
                    else:
                        print("Uninstallation cancelled.")
                else:
                    print("No extension name provided.")

            elif choice == "5":
                print("\n--- Allowed Extensions (Whitelist) ---")
                for ext in sorted(ALLOWED_EXTENSIONS):
                    print(f"  - {ext}")
                print(f"\nTotal: {len(ALLOWED_EXTENSIONS)} extensions")

            elif choice == "6":
                print("\n--- Batch Install Extensions ---")
                print("Enter extension names separated by commas:")
                ext_input = input("> ").strip()
                if ext_input:
                    ext_names = [e.strip().lower() for e in ext_input.split(",") if e.strip()]
                    print(f"\nExtensions to install: {', '.join(ext_names)}")
                    confirm = input("Proceed with installation? (yes/no): ").strip().lower()
                    if confirm == "yes":
                        success_count = 0
                        fail_count = 0
                        for ext_name in ext_names:
                            if install_extension(conn, ext_name):
                                success_count += 1
                            else:
                                fail_count += 1
                        print(
                            f"\nBatch complete: {success_count} succeeded, "
                            f"{fail_count} failed"
                        )
                    else:
                        print("Batch installation cancelled.")
                else:
                    print("No extensions provided.")

            elif choice == "7":
                print("Exiting PostgreSQL Extension Manager. Goodbye!")
                break

            else:
                print("Invalid option. Please select 1-7.")

    finally:
        if conn and not conn.closed:
            conn.close()
            print("Database connection closed.")


if __name__ == "__main__":
    main()